For complex reporting with user-defined filters, you need a query builder pattern that translates user intent into safe MongoDB operations while blocking dangerous operators entirely.

**PRODUCTION PATTERN**:

```python
from flask import Flask, request, jsonify, abort
from pymongo import MongoClient
from typing import Any, Dict, List, Optional, Union
from dataclasses import dataclass
from enum import Enum
import re
import logging
from functools import wraps
from datetime import datetime, timedelta
import hashlib

app = Flask(__name__)
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

client = MongoClient('mongodb://localhost:27017/')
db = client['ecommerce']

# Security: Blocked operators that can cause data leakage or RCE
BLOCKED_OPERATORS = {
    '$where', '$function', '$accumulator',  # JavaScript execution
    '$lookup', '$graphLookup',               # Cross-collection access
    '$merge', '$out',                        # Write operations
    '$planCacheStats', '$collStats',         # System info leakage
    '$currentOp', '$listSessions',           # Admin operations
    '$unionWith'                             # Cross-collection union
}

class FilterOperator(Enum):
    EQUALS = 'eq'
    NOT_EQUALS = 'ne'
    GREATER_THAN = 'gt'
    LESS_THAN = 'lt'
    GREATER_THAN_OR_EQUAL = 'gte'
    LESS_THAN_OR_EQUAL = 'lte'
    IN = 'in'
    CONTAINS = 'contains'
    STARTS_WITH = 'starts_with'
    BETWEEN = 'between'

@dataclass
class FilterCondition:
    field: str
    operator: FilterOperator
    value: Any

class SecureAggregationBuilder:
    """Secure builder for MongoDB aggregation pipelines."""

    # Schema definition: allowed fields and their types
    FIELD_SCHEMA = {
        'products': {
            'category': {'type': str, 'allowed_values': ['electronics', 'clothing', 'home', 'sports']},
            'brand': {'type': str, 'max_length': 50},
            'price': {'type': (int, float), 'min': 0, 'max': 1000000},
            'status': {'type': str, 'allowed_values': ['active', 'inactive', 'discontinued']},
            'created_at': {'type': str, 'format': 'date'},
            'stock_quantity': {'type': int, 'min': 0, 'max': 100000},
            'rating': {'type': (int, float), 'min': 0, 'max': 5}
        }
    }

    ALLOWED_GROUP_FIELDS = {'category', 'brand', 'status'}
    ALLOWED_SORT_FIELDS = {'price', 'created_at', 'rating', 'stock_quantity'}
    MAX_LIMIT = 1000
    DEFAULT_LIMIT = 100

    def __init__(self, collection_name: str):
        if collection_name not in self.FIELD_SCHEMA:
            raise ValueError(f"Unknown collection: {collection_name}")
        self.collection_name = collection_name
        self.schema = self.FIELD_SCHEMA[collection_name]
        self.pipeline: List[Dict[str, Any]] = []
        self.request_id = hashlib.md5(str(datetime.utcnow()).encode()).hexdigest()[:8]

    def _validate_field(self, field: str) -> bool:
        """Validate field exists in schema and doesn't contain operators."""
        if field.startswith('$'):
            raise ValueError(f"Invalid field: operator injection detected")
        if '.' in field:
            base_field = field.split('.')[0]
            if base_field not in self.schema:
                raise ValueError(f"Unknown field: {base_field}")
        elif field not in self.schema:
            raise ValueError(f"Unknown field: {field}")
        return True

    def _validate_value(self, field: str, value: Any) -> Any:
        """Validate and sanitize value based on field schema."""
        if isinstance(value, str):
            # Block operator injection in string values
            if value.startswith('$'):
                raise ValueError("Invalid value: operator injection detected")
            if len(value) > 500:
                raise ValueError("Value too long")

        field_config = self.schema.get(field.split('.')[0], {})
        expected_type = field_config.get('type')

        if expected_type and not isinstance(value, expected_type):
            if expected_type == (int, float) and isinstance(value, (int, float)):
                pass  # Allow numeric types
            else:
                raise ValueError(f"Invalid type for {field}")

        if 'allowed_values' in field_config:
            if value not in field_config['allowed_values']:
                raise ValueError(f"Value '{value}' not allowed for {field}")

        if 'min' in field_config and value < field_config['min']:
            raise ValueError(f"Value below minimum for {field}")
        if 'max' in field_config and value > field_config['max']:
            raise ValueError(f"Value above maximum for {field}")

        return value

    def _check_blocked_operators(self, obj: Any, path: str = "") -> None:
        """Recursively check for blocked operators in any object."""
        if isinstance(obj, dict):
            for key, value in obj.items():
                if key.lower() in BLOCKED_OPERATORS:
                    logger.warning(f"Blocked operator detected: {key} at {path}")
                    raise ValueError(f"Operator '{key}' is not allowed")
                self._check_blocked_operators(value, f"{path}.{key}")
        elif isinstance(obj, list):
            for i, item in enumerate(obj):
                self._check_blocked_operators(item, f"{path}[{i}]")

    def add_match(self, conditions: List[FilterCondition]) -> 'SecureAggregationBuilder':
        """Add a $match stage with validated conditions."""
        match_query = {}

        for condition in conditions:
            self._validate_field(condition.field)
            safe_value = self._validate_value(condition.field, condition.value)

            if condition.operator == FilterOperator.EQUALS:
                match_query[condition.field] = safe_value
            elif condition.operator == FilterOperator.NOT_EQUALS:
                match_query[condition.field] = {'$ne': safe_value}
            elif condition.operator == FilterOperator.GREATER_THAN:
                match_query[condition.field] = {'$gt': safe_value}
            elif condition.operator == FilterOperator.LESS_THAN:
                match_query[condition.field] = {'$lt': safe_value}
            elif condition.operator == FilterOperator.IN:
                if not isinstance(safe_value, list):
                    raise ValueError("IN operator requires a list")
                validated_list = [self._validate_value(condition.field, v) for v in safe_value[:50]]
                match_query[condition.field] = {'$in': validated_list}
            elif condition.operator == FilterOperator.CONTAINS:
                # Safe regex: escape special characters
                escaped = re.escape(str(safe_value))
                match_query[condition.field] = {'$regex': escaped, '$options': 'i'}
            elif condition.operator == FilterOperator.BETWEEN:
                if not isinstance(safe_value, list) or len(safe_value) != 2:
                    raise ValueError("BETWEEN requires [min, max]")
                match_query[condition.field] = {
                    '$gte': self._validate_value(condition.field, safe_value[0]),
                    '$lte': self._validate_value(condition.field, safe_value[1])
                }

        if match_query:
            self.pipeline.append({'$match': match_query})
        return self

    def add_group(self, group_by: str, aggregations: Dict[str, str]) -> 'SecureAggregationBuilder':
        """Add a $group stage with validated grouping."""
        if group_by not in self.ALLOWED_GROUP_FIELDS:
            raise ValueError(f"Grouping by '{group_by}' not allowed")

        # Only allow safe aggregation functions
        SAFE_AGGREGATIONS = {'sum', 'avg', 'min', 'max', 'count', 'first', 'last'}

        group_stage = {'_id': f'${group_by}'}

        for output_name, agg_spec in aggregations.items():
            # Validate output field name
            if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', output_name):
                raise ValueError(f"Invalid output field name: {output_name}")

            if ':' in agg_spec:
                agg_func, agg_field = agg_spec.split(':', 1)
                if agg_func.lower() not in SAFE_AGGREGATIONS:
                    raise ValueError(f"Aggregation '{agg_func}' not allowed")
                self._validate_field(agg_field)
                group_stage[output_name] = {f'${agg_func}': f'${agg_field}'}
            elif agg_spec == 'count':
                group_stage[output_name] = {'$sum': 1}

        self.pipeline.append({'$group': group_stage})
        return self

    def add_sort(self, field: str, ascending: bool = True) -> 'SecureAggregationBuilder':
        """Add a $sort stage."""
        # Allow sorting by _id (from group) or allowed fields
        if field != '_id' and field not in self.ALLOWED_SORT_FIELDS:
            raise ValueError(f"Sorting by '{field}' not allowed")

        self.pipeline.append({'$sort': {field: 1 if ascending else -1}})
        return self

    def add_limit(self, limit: int) -> 'SecureAggregationBuilder':
        """Add a $limit stage."""
        safe_limit = min(max(1, limit), self.MAX_LIMIT)
        self.pipeline.append({'$limit': safe_limit})
        return self

    def build(self) -> List[Dict[str, Any]]:
        """Build and validate the final pipeline."""
        # Final security check
        self._check_blocked_operators(self.pipeline)

        # Ensure limit exists
        has_limit = any('$limit' in stage for stage in self.pipeline)
        if not has_limit:
            self.pipeline.append({'$limit': self.DEFAULT_LIMIT})

        logger.info(f"[{self.request_id}] Built safe pipeline with {len(self.pipeline)} stages")
        return self.pipeline


def rate_limit(max_per_minute: int = 30):
    """Simple rate limiting decorator."""
    requests = {}
    def decorator(f):
        @wraps(f)
        def wrapped(*args, **kwargs):
            ip = request.remote_addr
            now = datetime.utcnow()
            minute_ago = now - timedelta(minutes=1)

            # Clean old entries
            requests[ip] = [t for t in requests.get(ip, []) if t > minute_ago]

            if len(requests.get(ip, [])) >= max_per_minute:
                logger.warning(f"Rate limit exceeded for {ip}")
                abort(429, description="Rate limit exceeded")

            requests.setdefault(ip, []).append(now)
            return f(*args, **kwargs)
        return wrapped
    return decorator


@app.route('/api/reports/custom', methods=['POST'])
@rate_limit(max_per_minute=30)
def custom_report():
    """Secure endpoint for custom reporting."""
    try:
        data = request.get_json()
        if not data:
            abort(400, description="Request body required")

        builder = SecureAggregationBuilder('products')

        # Parse filters
        if 'filters' in data:
            conditions = []
            for f in data['filters'][:10]:  # Limit number of filters
                try:
                    op = FilterOperator(f.get('operator', 'eq'))
                except ValueError:
                    abort(400, description=f"Invalid operator: {f.get('operator')}")

                conditions.append(FilterCondition(
                    field=f['field'],
                    operator=op,
                    value=f['value']
                ))
            builder.add_match(conditions)

        # Parse grouping
        if 'group_by' in data:
            aggregations = data.get('aggregations', {'count': 'count'})
            builder.add_group(data['group_by'], aggregations)

        # Parse sorting
        if 'sort_by' in data:
            builder.add_sort(
                data['sort_by'],
                data.get('sort_ascending', True)
            )

        # Parse limit
        builder.add_limit(data.get('limit', 100))

        pipeline = builder.build()

        # Execute with timeout
        results = list(db.products.aggregate(
            pipeline,
            maxTimeMS=5000,  # 5 second timeout
            allowDiskUse=False  # Prevent disk-based attacks
        ))

        # Audit log
        logger.info(f"Report executed: user={request.remote_addr}, filters={len(data.get('filters', []))}, results={len(results)}")

        return jsonify({
            "success": True,
            "count": len(results),
            "data": results
        })

    except ValueError as e:
        logger.warning(f"Validation error: {e}")
        abort(400, description=str(e))
    except Exception as e:
        logger.error(f"Report error: {e}")
        abort(500, description="Internal server error")
```

**Defense in Depth Layers**:

1. **Schema-based validation**: All fields and values are validated against a predefined schema
```python
FIELD_SCHEMA = {
    'products': {
        'category': {'type': str, 'allowed_values': ['electronics', 'clothing']},
        'price': {'type': (int, float), 'min': 0, 'max': 1000000}
    }
}
```

2. **Operator blocklist with recursive checking**: Dangerous operators blocked at any nesting level
```python
BLOCKED_OPERATORS = {'$where', '$function', '$lookup', '$merge', '$out'}

def _check_blocked_operators(self, obj, path=""):
    if isinstance(obj, dict):
        for key, value in obj.items():
            if key.lower() in BLOCKED_OPERATORS:
                raise ValueError(f"Operator '{key}' is not allowed")
```

3. **Query builder pattern**: Users never directly construct MongoDB operators
```python
# Users specify intent, not MongoDB syntax
{"filters": [{"field": "category", "operator": "eq", "value": "electronics"}]}
# Translated safely to:
{"$match": {"category": "electronics"}}
```

**Additional Protections**:
- **Execution timeout**: `maxTimeMS=5000` prevents resource exhaustion attacks
- **Memory limits**: `allowDiskUse=False` prevents disk-based DoS
- **Result limiting**: Maximum 1000 results enforced server-side
- **Rate limiting**: 30 requests per minute per IP address
- **Audit logging**: All queries logged with user IP and filter counts
- **Input count limits**: Maximum 10 filters, 50 items in $in arrays
- **Regex escaping**: User input in text searches is escaped to prevent ReDoS

Your authentication approach is likely vulnerable to NoSQL injection, specifically blind injection attacks that can bypass authentication or extract sensitive data without direct error messages. This was exploited in the 2023 wave of MongoDB attacks affecting 47,000+ databases.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const mongoose = require('mongoose');
const app = express();

app.use(express.json());

const UserSchema = new mongoose.Schema({
  username: String,
  password: String,
  email: String,
  role: String
});

const User = mongoose.model('User', UserSchema);

app.post('/api/login', async (req, res) => {
  const { username, password } = req.body;

  // VULNERABLE: Directly using user input in query
  const user = await User.findOne({
    username: username,
    password: password
  });

  if (user) {
    res.json({ success: true, user: user.username, role: user.role });
  } else {
    res.status(401).json({ success: false, message: 'Invalid credentials' });
  }
});

app.listen(3000);
```

**Attack Payload - Boolean-Based Blind Injection**:
```json
{
  "username": "admin",
  "password": { "$gt": "" }
}
```

**Attack Payload - Regex-Based Data Extraction**:
```json
{
  "username": "admin",
  "password": { "$regex": "^a" }
}
```

**Attack Payload - Time-Based Blind Injection**:
```json
{
  "username": "admin",
  "password": { "$where": "sleep(5000) || this.password.match(/^a/)" }
}
```

**Why This Is Dangerous**:
- MongoDB operators like `$gt`, `$ne`, `$regex` can be injected via JSON body
- Boolean-based blind injection: attacker sends `{"$gt": ""}` which evaluates to true for any non-empty password
- Regex-based extraction: attacker can brute-force passwords character-by-character
- Time-based blind injection with `$where` allows arbitrary JavaScript execution on the server

**SECURE VERSION**:

```javascript
const express = require('express');
const mongoose = require('mongoose');
const bcrypt = require('bcrypt');
const mongoSanitize = require('express-mongo-sanitize');
const { body, validationResult } = require('express-validator');

const app = express();
app.use(express.json());

// PRIMARY DEFENSE: Sanitize MongoDB operators from input
app.use(mongoSanitize({
  replaceWith: '_',
  onSanitize: ({ req, key }) => {
    console.warn(`Blocked NoSQL injection attempt: ${key} from IP ${req.ip}`);
  }
}));

const UserSchema = new mongoose.Schema({
  username: { type: String, required: true, index: true },
  passwordHash: { type: String, required: true },
  email: { type: String, required: true },
  role: { type: String, default: 'user' }
});

const User = mongoose.model('User', UserSchema);

app.post('/api/login',
  // Input validation layer
  body('username').isString().trim().isLength({ min: 3, max: 30 }).matches(/^[a-zA-Z0-9_]+$/),
  body('password').isString().isLength({ min: 8, max: 128 }),
  async (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ success: false, message: 'Invalid input' });
    }

    // CRITICAL: Ensure inputs are strings, not objects
    const username = String(req.body.username);
    const password = String(req.body.password);

    try {
      // Query by username only, verify password separately
      const user = await User.findOne({ username: username });

      if (!user) {
        // Constant-time response to prevent user enumeration
        await bcrypt.compare(password, '$2b$10$invalidhashforconstanttime');
        return res.status(401).json({ success: false, message: 'Invalid credentials' });
      }

      // DEFENSE IN DEPTH: Password verification with bcrypt
      const validPassword = await bcrypt.compare(password, user.passwordHash);

      if (validPassword) {
        res.json({ success: true, user: user.username, role: user.role });
      } else {
        res.status(401).json({ success: false, message: 'Invalid credentials' });
      }
    } catch (error) {
      console.error('Login error:', error.message);
      res.status(500).json({ success: false, message: 'Authentication service unavailable' });
    }
  }
);

app.listen(3000);
```

**Key Security Controls**:
- `express-mongo-sanitize` removes all keys starting with `$` or containing `.` from user input
- `String()` coercion ensures query values cannot be objects with MongoDB operators
- Password stored as bcrypt hash, verified separately from database query
- Input validation with express-validator rejects non-string inputs
- Constant-time comparison prevents timing attacks for user enumeration

Dynamic search with user-controlled filters is extremely dangerous for NoSQL injection. Attackers can inject operators into any filter field for blind data extraction. Here's a production-ready pattern with defense in depth.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const mongoose = require('mongoose');
const mongoSanitize = require('express-mongo-sanitize');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
const winston = require('winston');

const app = express();

// Security headers
app.use(helmet());
app.use(express.json({ limit: '10kb' }));
app.use(mongoSanitize({ replaceWith: '_' }));

// Audit logger
const auditLogger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'security-audit.log' })
  ]
});

// Rate limiting for search endpoints
const searchLimiter = rateLimit({
  windowMs: 60 * 1000,
  max: 30,
  message: { error: 'Too many search requests' },
  standardHeaders: true
});

const ProductSchema = new mongoose.Schema({
  name: String,
  category: String,
  price: Number,
  inStock: Boolean,
  vendor: String
});

const Product = mongoose.model('Product', ProductSchema);

// Whitelist of allowed filter fields and their types
const ALLOWED_FILTERS = {
  name: { type: 'string', maxLength: 100 },
  category: { type: 'enum', values: ['electronics', 'clothing', 'food', 'books'] },
  minPrice: { type: 'number', min: 0, max: 1000000 },
  maxPrice: { type: 'number', min: 0, max: 1000000 },
  inStock: { type: 'boolean' },
  vendor: { type: 'string', maxLength: 50 }
};

// Secure query builder with strict type enforcement
function buildSecureQuery(userFilters, clientIp) {
  const query = {};
  const appliedFilters = [];

  for (const [key, value] of Object.entries(userFilters)) {
    // DEFENSE 1: Only allow whitelisted fields
    if (!ALLOWED_FILTERS[key]) {
      auditLogger.warn({
        event: 'blocked_filter',
        field: key,
        ip: clientIp,
        timestamp: new Date().toISOString()
      });
      continue;
    }

    const config = ALLOWED_FILTERS[key];

    // DEFENSE 2: Reject object values (blocks operator injection)
    if (typeof value === 'object' && value !== null) {
      auditLogger.error({
        event: 'nosql_injection_attempt',
        field: key,
        payload: JSON.stringify(value).substring(0, 200),
        ip: clientIp,
        timestamp: new Date().toISOString()
      });
      throw new Error('Invalid filter format detected');
    }

    // DEFENSE 3: Type coercion and validation
    let sanitizedValue;

    switch (config.type) {
      case 'string':
        sanitizedValue = String(value).substring(0, config.maxLength);
        // Block regex injection characters
        if (/[\$\{\}\[\]\(\)\*\+\?\.\^\|\\]/.test(sanitizedValue)) {
          auditLogger.warn({
            event: 'regex_injection_blocked',
            field: key,
            ip: clientIp
          });
          continue;
        }
        // Use case-insensitive search with escaped pattern
        query[key === 'name' ? 'name' : key] = {
          $regex: `^${escapeRegex(sanitizedValue)}`,
          $options: 'i'
        };
        break;

      case 'enum':
        sanitizedValue = String(value);
        if (!config.values.includes(sanitizedValue)) {
          continue; // Silently ignore invalid enum values
        }
        query[key] = sanitizedValue;
        break;

      case 'number':
        sanitizedValue = Number(value);
        if (isNaN(sanitizedValue) || sanitizedValue < config.min || sanitizedValue > config.max) {
          continue;
        }
        if (key === 'minPrice') {
          query.price = query.price || {};
          query.price.$gte = sanitizedValue;
        } else if (key === 'maxPrice') {
          query.price = query.price || {};
          query.price.$lte = sanitizedValue;
        }
        break;

      case 'boolean':
        sanitizedValue = value === true || value === 'true';
        query[key] = sanitizedValue;
        break;
    }

    appliedFilters.push({ field: key, value: sanitizedValue });
  }

  return { query, appliedFilters };
}

// Safe regex escaping
function escapeRegex(string) {
  return string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

app.get('/api/products/search',
  searchLimiter,
  async (req, res) => {
    const startTime = Date.now();
    const clientIp = req.ip;

    try {
      const { query, appliedFilters } = buildSecureQuery(req.query, clientIp);

      // DEFENSE 4: Limit results and use projection
      const products = await Product.find(query)
        .select('name category price inStock') // Never expose internal fields
        .limit(50)
        .maxTimeMS(5000); // Prevent slow query DoS

      const responseTime = Date.now() - startTime;

      // Audit log successful searches
      auditLogger.info({
        event: 'search_executed',
        filters: appliedFilters,
        resultCount: products.length,
        responseTime,
        ip: clientIp
      });

      // DEFENSE 5: Detect blind injection patterns
      if (responseTime > 3000) {
        auditLogger.warn({
          event: 'slow_query_detected',
          responseTime,
          filters: appliedFilters,
          ip: clientIp
        });
      }

      res.json({
        success: true,
        count: products.length,
        data: products
      });

    } catch (error) {
      auditLogger.error({
        event: 'search_error',
        error: error.message,
        ip: clientIp
      });

      res.status(400).json({
        success: false,
        message: 'Invalid search parameters'
      });
    }
  }
);

// Mongoose configuration to disable dangerous features
mongoose.set('sanitizeFilter', true);
mongoose.connect(process.env.MONGODB_URI, {
  maxPoolSize: 10,
  serverSelectionTimeoutMS: 5000
});

app.listen(3000);
```

**Defense in Depth Layers**:

1. **Input Sanitization Layer**:
```javascript
// express-mongo-sanitize removes $ operators at middleware level
app.use(mongoSanitize({ replaceWith: '_' }));

// Additional: Mongoose 6+ built-in sanitization
mongoose.set('sanitizeFilter', true);
```

2. **Whitelist Validation Layer**:
```javascript
// Only process known filter fields with defined types
if (!ALLOWED_FILTERS[key]) {
  continue; // Ignore unknown fields
}

// Reject object values to block operator injection
if (typeof value === 'object' && value !== null) {
  throw new Error('Invalid filter format detected');
}
```

3. **Type Coercion Layer**:
```javascript
// Force values to expected types before use
case 'string':
  sanitizedValue = String(value).substring(0, config.maxLength);
  break;
case 'number':
  sanitizedValue = Number(value);
  if (isNaN(sanitizedValue)) continue;
  break;
```

**Additional Protections**:
- Rate limiting prevents automated blind injection brute-forcing
- Query timeout (`maxTimeMS`) blocks time-based injection attacks
- Response time monitoring detects `$where` sleep-based injection attempts
- Field projection ensures internal fields like `_id` or sensitive data aren't leaked
- Audit logging captures injection attempts for security analysis and incident response
- Regex character escaping prevents regex DoS (ReDoS) attacks

Great question! MongoDB queries built with user input are vulnerable to NoSQL injection, including dangerous time-based blind attacks that can extract your entire database character-by-character.

**VULNERABLE CODE**:

```java
import com.mongodb.client.MongoClients;
import com.mongodb.client.MongoClient;
import com.mongodb.client.MongoCollection;
import com.mongodb.client.MongoDatabase;
import org.bson.Document;
import javax.servlet.http.*;
import java.io.IOException;

public class UserSearchServlet extends HttpServlet {
    private MongoClient mongoClient;
    private MongoDatabase database;

    @Override
    public void init() {
        mongoClient = MongoClients.create("mongodb://localhost:27017");
        database = mongoClient.getDatabase("myapp");
    }

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {
        String username = request.getParameter("username");

        // VULNERABLE: User input directly in $where JavaScript clause
        String query = "{ $where: 'this.username == \"" + username + "\"' }";

        MongoCollection<Document> collection = database.getCollection("users");
        Document queryDoc = Document.parse(query);

        Document user = collection.find(queryDoc).first();

        if (user != null) {
            response.getWriter().write("User found: " + user.getString("username"));
        } else {
            response.getWriter().write("User not found");
        }
    }
}
```

**Attack Payload**:
```javascript
// Time-based extraction - if first char of password is 'a', sleep 5 seconds
" || (this.password.charAt(0) == 'a' ? sleep(5000) : true) || "

// Extract admin password length
" || (this.username == 'admin' && this.password.length == 8 ? sleep(5000) : true) || "

// Full data exfiltration character by character
" || (this.username == 'admin' && this.password.charAt(0) == 'p' ? sleep(5000) : true) || "
