import org.slf4j.LoggerFactory;

public class SecureUserSearchServlet extends HttpServlet {
    private static final Logger logger = LoggerFactory.getLogger(SecureUserSearchServlet.class);
    private static final Pattern VALID_USERNAME = Pattern.compile("^[a-zA-Z0-9_]{3,30}$");

    private MongoClient mongoClient;
    private MongoDatabase database;

    @Override
    public void init() {
        mongoClient = MongoClients.create("mongodb://localhost:27017");
        database = mongoClient.getDatabase("myapp");
    }

