        if (username == null || !VALID_USERNAME.matcher(username).matches()) {
            logger.warn("Invalid username format attempted: {}", 
                       username != null ? username.substring(0, Math.min(50, username.length())) : "null");
            response.setStatus(HttpServletResponse.SC_BAD_REQUEST);
            response.getWriter().write("Invalid username format");
            return;
        }

        try {
            MongoCollection<Document> collection = database.getCollection("users");

            // SECURE: Use typed Filters API - never $where
            Bson filter = Filters.eq("username", username);

            Document user = collection.find(filter).first();

            if (user != null) {
                logger.info("User lookup successful for: {}", username);
                response.getWriter().write("User found: " + user.getString("username"));
            } else {
                response.getWriter().write("User not found");
