// Secure command execution wrapper
class SecureCommandExecutor {
  constructor(options = {}) {
    this.timeout = options.timeout || 30000;
    this.maxBuffer = options.maxBuffer || 10 * 1024 * 1024;
    this.allowedCommands = new Set(options.allowedCommands || []);
  }

  async execute(command, args, options = {}) {
    // Validate command is in allowlist
    if (!this.allowedCommands.has(command)) {
      throw new Error(`Command not allowed: ${command}`);
    }

    // Validate all arguments are strings (no injection via objects)
    if (!args.every(arg => typeof arg === 'string')) {
      throw new Error('Invalid argument types');
    }

    return new Promise((resolve, reject) => {
      const proc = spawn(command, args, {
        timeout: this.timeout,
        maxBuffer: this.maxBuffer,
        cwd: options.cwd || '/app',
        env: { PATH: '/usr/bin:/bin' }, // Minimal PATH
        stdio: ['pipe', 'pipe', 'pipe']
      });

      let stdout = '';
      let stderr = '';

      proc.stdout.on('data', (data) => {
        stdout += data.toString();
      });

      proc.stderr.on('data', (data) => {
        stderr += data.toString();
      });

      proc.on('close', (code) => {
        if (code === 0) {
          resolve({ stdout, stderr, code });
        } else {
          reject(new Error(`Process exited with code ${code}: ${stderr}`));
        }
      });

      proc.on('error', reject);
    });
  }

  // SECURE: Pipe multiple commands without shell
  async pipe(commands) {
    return new Promise((resolve, reject) => {
      const processes = [];
      let lastProc = null;

      for (let i = 0; i < commands.length; i++) {
        const { command, args } = commands[i];

        if (!this.allowedCommands.has(command)) {
          return reject(new Error(`Command not allowed: ${command}`));
        }

        const proc = spawn(command, args, {
          stdio: [
            i === 0 ? 'pipe' : lastProc.stdout,
            i === commands.length - 1 ? 'pipe' : 'pipe',
            'pipe'
          ],
          env: { PATH: '/usr/bin:/bin' }
        });

        processes.push(proc);
        lastProc = proc;
      }

      let output = '';
      lastProc.stdout.on('data', (data) => {
        output += data.toString();
      });

      lastProc.on('close', (code) => {
        if (code === 0) {
          resolve(output);
        } else {
          reject(new Error(`Pipeline failed with code ${code}`));
        }
      });
    });
  }
}

