**PRODUCTION PATTERN**:

```java
import javax.servlet.http.*;
import java.io.*;
import java.nio.charset.StandardCharsets;
import java.util.regex.Pattern;
import java.util.logging.Logger;
import java.util.UUID;

public class SecureHeaderService {

    private static final Logger logger = Logger.getLogger(SecureHeaderService.class.getName());

    // Pattern for valid filename characters (alphanumeric, dash, underscore, dot)
    private static final Pattern SAFE_FILENAME_PATTERN = Pattern.compile("^[a-zA-Z0-9._-]{1,255}$");

    // Pattern for valid header values (printable ASCII, no control characters)
    private static final Pattern SAFE_HEADER_VALUE_PATTERN = Pattern.compile("^[\\x20-\\x7E]{0,1000}$");

    // Characters that must never appear in headers
    private static final Pattern DANGEROUS_CHARS = Pattern.compile("[\\r\\n\\x00]");

    /**
     * Safely sets Content-Disposition header for file downloads
     */
    public void setContentDisposition(HttpServletResponse response, String filename, 
                                       String requestId) {

        String sanitizedFilename = sanitizeFilename(filename);

        if (sanitizedFilename == null) {
            // Fall back to generic filename
            sanitizedFilename = "download_" + System.currentTimeMillis();
            logger.warning("RequestId=" + requestId + 
                          " Invalid filename rejected, using fallback");
        }

        // RFC 6266 compliant Content-Disposition with both filename and filename*
        String headerValue = String.format(
            "attachment; filename=\"%s\"; filename*=UTF-8''%s",
            sanitizedFilename,
            encodeRFC5987(sanitizedFilename)
        );

        response.setHeader("Content-Disposition", headerValue);

        logger.info("RequestId=" + requestId + " Set Content-Disposition: " + sanitizedFilename);
    }

    /**
     * Safely sets custom tracking/correlation headers
     */
    public void setTrackingHeaders(HttpServletResponse response, 
                                    HttpServletRequest request,
                                    String correlationId) {

        // LAYER 1: Generate safe correlation ID if not provided or invalid
        String safeCorrelationId = sanitizeHeaderValue(correlationId);
        if (safeCorrelationId == null || safeCorrelationId.isEmpty()) {
            safeCorrelationId = UUID.randomUUID().toString();
        }

        // LAYER 2: Use enum-based header names to prevent header name injection
        response.setHeader(TrackingHeader.CORRELATION_ID.getName(), safeCorrelationId);

        // LAYER 3: Timestamp is generated server-side, not from user input
        response.setHeader(TrackingHeader.TIMESTAMP.getName(), 
                          String.valueOf(System.currentTimeMillis()));

        // LAYER 4: Safe extraction of client info
        String clientIp = getClientIp(request);
        response.setHeader(TrackingHeader.CLIENT_IP.getName(), clientIp);
    }

    /**
     * Sanitizes filename for use in Content-Disposition header
     */
    private String sanitizeFilename(String filename) {
        if (filename == null || filename.isEmpty()) {
            return null;
        }

        // CRITICAL: Check for CRLF injection attempts
        if (DANGEROUS_CHARS.matcher(filename).find()) {
            logger.severe("CRLF injection attempt detected in filename");
            return null;
        }

        // Remove path traversal attempts
        String cleaned = filename
            .replaceAll("\\.\\.", "")
            .replaceAll("[/\\\\]", "")
            .trim();

        // Extract just the filename if it contains path separators
        int lastSlash = Math.max(cleaned.lastIndexOf('/'), cleaned.lastIndexOf('\\'));
        if (lastSlash >= 0) {
            cleaned = cleaned.substring(lastSlash + 1);
        }

        // Validate against safe pattern
        if (!SAFE_FILENAME_PATTERN.matcher(cleaned).matches()) {
            // Try to create a safe version by removing invalid chars
            cleaned = cleaned.replaceAll("[^a-zA-Z0-9._-]", "_");
            if (cleaned.isEmpty() || cleaned.length() > 255) {
                return null;
            }
        }

        return cleaned;
    }

    /**
     * Sanitizes arbitrary string for use as HTTP header value
     */
    private String sanitizeHeaderValue(String value) {
        if (value == null) {
            return null;
        }

        // CRITICAL: Reject any control characters including CRLF
        if (DANGEROUS_CHARS.matcher(value).find()) {
            logger.severe("CRLF injection attempt detected in header value");
            return null;
        }

        // URL decode to catch encoded attacks
        String decoded;
        try {
            decoded = java.net.URLDecoder.decode(value, StandardCharsets.UTF_8.name());
            if (DANGEROUS_CHARS.matcher(decoded).find()) {
                logger.severe("Encoded CRLF injection attempt detected");
                return null;
            }
        } catch (Exception e) {
            // If decoding fails, proceed with original value validation
            decoded = value;
        }

        // Validate against safe header pattern
        if (!SAFE_HEADER_VALUE_PATTERN.matcher(value).matches()) {
            return null;
        }

        return value;
    }

    /**
     * RFC 5987 encoding for non-ASCII characters in headers
     */
    private String encodeRFC5987(String value) {
        StringBuilder sb = new StringBuilder();
        for (byte b : value.getBytes(StandardCharsets.UTF_8)) {
            char c = (char) (b & 0xff);
            if ((c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z') || 
                (c >= '0' && c <= '9') || c == '.' || c == '-' || c == '_') {
                sb.append(c);
            } else {
                sb.append(String.format("%%%02X", b));
            }
        }
        return sb.toString();
    }

    /**
     * Safely extracts client IP, handling proxies
     */
    private String getClientIp(HttpServletRequest request) {
        String ip = request.getHeader("X-Forwarded-For");
        if (ip != null && !ip.isEmpty()) {
            // Take first IP in chain and validate format
            ip = ip.split(",")[0].trim();
            if (!isValidIp(ip)) {
                ip = request.getRemoteAddr();
            }
        } else {
            ip = request.getRemoteAddr();
        }
        return sanitizeHeaderValue(ip) != null ? ip : "unknown";
    }

    private boolean isValidIp(String ip) {
        // Basic IP validation (IPv4 or IPv6)
        return ip.matches("^[0-9a-fA-F.:]{7,45}$");
    }

    /**
     * Enum for safe header names - prevents header name injection
     */
    private enum TrackingHeader {
        CORRELATION_ID("X-Correlation-ID"),
        TIMESTAMP("X-Request-Timestamp"),
        CLIENT_IP("X-Client-IP");

        private final String name;

        TrackingHeader(String name) {
            this.name = name;
        }

        public String getName() {
            return name;
        }
    }
}
```

